def validate_cart_items(cart_items: List[CartItem]) -> ValidatedCart:
    if not cart_items:
        raise CartValidationError("Cart is empty.")

    subtotal = Decimal("0.00")
    taxable_subtotal = Decimal("0.00")
    item_count = 0

    for item in cart_items:
        if not item.active:
            raise CartValidationError(f"Item '{item.sku}' is inactive.")
        if item.quantity <= 0:
            raise CartValidationError(f"Item '{item.sku}' has invalid quantity.")
        if item.unit_price < 0:
            raise CartValidationError(f"Item '{item.sku}' has invalid unit price.")
        if item.stock < item.quantity:
            raise CartValidationError(f"Item '{item.sku}' is out of stock.")
        line_total = item.subtotal()
        subtotal += line_total
        if item.taxable:
            taxable_subtotal += line_total
        item_count += item.quantity

    return ValidatedCart(
        items=cart_items,
        subtotal=money(subtotal),
        taxable_subtotal=money(taxable_subtotal),
        item_count=item_count,
    )


def apply_discount_code(
    user: User,
    validated_cart: ValidatedCart,
    discount_code: Optional[str],
    discount_catalog: Dict[str, DiscountCode],
) -> DiscountResult:
    if not discount_code:
        return DiscountResult(
            code=None,
            discount_amount=Decimal("0.00"),
            discounted_subtotal=validated_cart.subtotal,
            discounted_taxable_subtotal=validated_cart.taxable_subtotal,
            details={"applied": False},
        )

    code_key = discount_code.upper().strip()
    discount = discount_catalog.get(code_key)
    if not discount:
        raise DiscountValidationError("Discount code does not exist.")
    if not discount.is_allowed_for_user(user):
        raise DiscountPermissionError("User is not allowed to use this discount code.")
    if validated_cart.subtotal < money(discount.min_subtotal):
        raise DiscountValidationError("Cart does not meet minimum subtotal for this discount.")

    eligible_subtotal = Decimal("0.00")
    eligible_taxable_subtotal = Decimal("0.00")

    if discount.applicable_skus:
        applicable = set(discount.applicable_skus)
        for item in validated_cart.items:
            if item.sku in applicable:
                eligible_subtotal += item.subtotal()
                if item.taxable:
                    eligible_taxable_subtotal += item.subtotal()
    else:
        eligible_subtotal = validated_cart.subtotal
        eligible_taxable_subtotal = validated_cart.taxable_subtotal

    eligible_subtotal = money(eligible_subtotal)
    eligible_taxable_subtotal = money(eligible_taxable_subtotal)

    if eligible_subtotal <= 0:
        raise DiscountValidationError("Discount code is not applicable to cart items.")

    if discount.kind == "percent":
        discount_amount = money(eligible_subtotal * (discount.value / Decimal("100")))
    elif discount.kind == "fixed":
        discount_amount = min(money(discount.value), eligible_subtotal)
    else:
        raise DiscountValidationError("Unsupported discount type.")

    discount_amount = min(discount_amount, validated_cart.subtotal)

    taxable_discount_share = Decimal("0.00")
    if eligible_subtotal > 0 and eligible_taxable_subtotal > 0:
        ratio = eligible_taxable_subtotal / eligible_subtotal
        taxable_discount_share = money(discount_amount * ratio)

    discounted_subtotal = money(validated_cart.subtotal - discount_amount)
    discounted_taxable_subtotal = money(max(Decimal("0.00"), validated_cart.taxable_subtotal - taxable_discount_share))

    return DiscountResult(
        code=code_key,
        discount_amount=money(discount_amount),
        discounted_subtotal=discounted_subtotal,
        discounted_taxable_subtotal=discounted_taxable_subtotal,
        details={
            "applied": True,
            "kind": discount.kind,
            "value": str(discount.value),
            "eligible_subtotal": str(eligible_subtotal),
        },
    )


def calculate_tax(discount_result: DiscountResult, tax_rate: Decimal) -> TaxResult:
    rate = money(tax_rate)
    if rate < 0:
        raise CheckoutError("Tax rate cannot be negative.")
    tax_amount = money(discount_result.discounted_taxable_subtotal * (rate / Decimal("100")))
    total_before_payment = money(discount_result.discounted_subtotal + tax_amount)
    return TaxResult(
        tax_rate=rate,
        tax_amount=tax_amount,
        total_before_payment=total_before_payment,
    )


def process_payment(payment_method: PaymentMethod, amount: Decimal) -> PaymentResult:
    amount = money(amount)
    if amount <= 0:
        raise PaymentProcessingError("Payment amount must be greater than zero.")
    if not payment_method.valid or not payment_method.token:
        raise PaymentProcessingError("Invalid payment method.")
    return PaymentResult(
        payment_id=f"pay_{uuid.uuid4().hex[:16]}",
        status="paid",
        charged_amount=amount,
        method_type=payment_method.method_type,
    )


def create_order_record(
    user: User,
    validated_cart: ValidatedCart,
    discount_result: DiscountResult,
    tax_result: TaxResult,
    payment_result: PaymentResult,
) -> OrderRecord:
    return OrderRecord(
        order_id=f"ord_{uuid.uuid4().hex[:16]}",
        user_id=user.user_id,
        items=[
            {
                "sku": item.sku,
                "name": item.name,
                "unit_price": str(money(item.unit_price)),
                "quantity": item.quantity,
                "line_total": str(item.subtotal()),
                "taxable": item.taxable,
            }
            for item in validated_cart.items
        ],
        subtotal=validated_cart.subtotal,
        discount_code=discount_result.code,
        discount_amount=discount_result.discount_amount,
        tax_rate=tax_result.tax_rate,
        tax_amount=tax_result.tax_amount,
        total=payment_result.charged_amount,
        payment_id=payment_result.payment_id,
        created_at=datetime.datetime.utcnow().isoformat() + "Z",
        metadata={
            "payment_status": payment_result.status,
            "item_count": validated_cart.item_count,
            "discount_details": discount_result.details,
        },
    )


def checkout(
    user: User,
    cart_items: List[CartItem],
    payment_method: PaymentMethod,
    tax_rate: Decimal,
    discount_code: Optional[str] = None,
    discount_catalog: Optional[Dict[str, DiscountCode]] = None,
) -> Dict[str, Any]:
    discount_catalog = discount_catalog or {}

    validated_cart = validate_cart_items(cart_items)
    discount_result = apply_discount_code(
        user=user,
        validated_cart=validated_cart,
        discount_code=discount_code,
        discount_catalog=discount_catalog,
    )
    tax_result = calculate_tax(discount_result, tax_rate)
    payment_result = process_payment(payment_method, tax_result.total_before_payment)
    order_record = create_order_record(
        user=user,
        validated_cart=validated_cart,
        discount_result=discount_result,
        tax_result=tax_result,
        payment_result=payment_result,
    )

    return {
        "validated_cart": validated_cart,
        "discount_result": discount_result,
        "tax_result": tax_result,
        "payment_result": payment_result,
        "order_record": order_record,
    }


